async () => {
    const note = 'detox-smoke-note';
    await waitFor(element(by.id('dashboard-add-expense-button'))).toBeVisible().withTimeout(10000);
    await element(by.id('dashboard-add-expense-button')).tap();
    await waitFor(element(by.id('add-expense-amount-input'))).toBeVisible().withTimeout(10000);
    await element(by.id('add-expense-amount-input')).replaceText('12.34');
    await waitFor(element(by.id('category-grid-item-default-food'))).toBeVisible().withTimeout(10000);
    await element(by.id('category-grid-item-default-food')).tap();
    await waitFor(element(by.id('add-expense-note-toggle'))).toBeVisible().withTimeout(10000);
    await element(by.id('add-expense-note-toggle')).tap();
    await waitFor(element(by.id('add-expense-note-input'))).toBeVisible().withTimeout(10000);
    await element(by.id('add-expense-note-input')).replaceText(note);
    await element(by.id('add-expense-save-button')).tap();
    await waitFor(element(by.id('dashboard-summary-spent-card'))).toBeVisible().withTimeout(10000);
    await element(by.id('dashboard-view-transactions-button')).tap();
    await waitFor(element(by.text(note))).toBeVisible().withTimeout(10000);
  }

